+final class PasteSessionCapturer: PasteSessionCapturing {
+    private let accessibilityChecker: any AccessibilityPermissionChecking
+    private let applicationProvider: any FrontmostApplicationProviding
+    private let windowResolver: any FrontmostWindowResolving
+    private let applicationFactory: any AccessibilityApplicationCreating
+    private let dateProvider: any DateProviding
+    private let focusedElementResolver = FocusedElementResolver()
+    private let textExtractor = FocusedElementTextExtractor()
+
+    init(
+        accessibilityChecker: any AccessibilityPermissionChecking = AccessibilityPermissionChecker(),
+        applicationProvider: any FrontmostApplicationProviding = WorkspaceFrontmostApplicationProvider(),
+        windowResolver: any FrontmostWindowResolving = CoreGraphicsFrontmostWindowResolver(),
+        applicationFactory: any AccessibilityApplicationCreating = AXAccessibilityApplicationFactory(),
+        dateProvider: any DateProviding = SystemDateProvider()
+    ) {
+        self.accessibilityChecker = accessibilityChecker
+        self.applicationProvider = applicationProvider
+        self.windowResolver = windowResolver
+        self.applicationFactory = applicationFactory
+        self.dateProvider = dateProvider
+    }
+
+    func capture(pastedText: String) -> PasteSessionSnapshot? {
+        guard accessibilityChecker.isTrusted(prompt: false) else {
+            return nil
+        }
+
+        guard let applicationContext = applicationProvider.frontmostApplication() else {
+            return nil
+        }
+
+        let windowContext = windowResolver.frontmostWindow(for: applicationContext.processID)
+        let application = applicationFactory.application(processID: applicationContext.processID)
+        let resolution = focusedElementResolver.resolve(in: application)
+        let focusedElement = resolution.directElement ?? resolution.fallbackElement
+
+        return PasteSessionSnapshot(
+            pastedText: pastedText,
+            timestamp: dateProvider.currentDate(),
+            applicationBundleIdentifier: applicationContext.bundleIdentifier,
+            windowID: windowContext?.windowID,
+            windowFrame: windowContext?.frame,
+            focusedElementFrame: focusedElement?.frame,
+            focusedElementText: focusedElement.flatMap(textExtractor.extractText(from:))
+        )
+    }
+}

