+import CoreGraphics
+import Foundation
+
+protocol EventSourceCreating {
+    func make(stateID: CGEventSourceStateID) -> CGEventSource?
+}
+
+protocol KeyboardEventCreating {
+    func make(source: CGEventSource, virtualKey: CGKeyCode, keyDown: Bool) -> CGEvent?
+}
+
+protocol EventPosting {
+    func post(_ event: CGEvent, tap: CGEventTapLocation)
+}
+
+struct CoreGraphicsEventSourceFactory: EventSourceCreating {
+    func make(stateID: CGEventSourceStateID) -> CGEventSource? {
+        CGEventSource(stateID: stateID)
+    }
+}
+
+struct CoreGraphicsKeyboardEventFactory: KeyboardEventCreating {
+    func make(source: CGEventSource, virtualKey: CGKeyCode, keyDown: Bool) -> CGEvent? {
+        CGEvent(keyboardEventSource: source, virtualKey: virtualKey, keyDown: keyDown)
+    }
+}
+
+struct CoreGraphicsEventPoster: EventPosting {
+    func post(_ event: CGEvent, tap: CGEventTapLocation) {
+        event.post(tap: tap)
+    }
+}
+
+final class CommandVPasteKeystrokePreparer: PasteKeystrokePreparing {
+    private let sourceFactory: any EventSourceCreating
+    private let eventFactory: any KeyboardEventCreating
+    private let poster: any EventPosting
+
+    init(
+        sourceFactory: any EventSourceCreating = CoreGraphicsEventSourceFactory(),
+        eventFactory: any KeyboardEventCreating = CoreGraphicsKeyboardEventFactory(),
+        poster: any EventPosting = CoreGraphicsEventPoster()
+    ) {
+        self.sourceFactory = sourceFactory
+        self.eventFactory = eventFactory
+        self.poster = poster
+    }
+
+    func makePreparedPaste() -> PreparedPasteAction? {
+        guard let source = sourceFactory.make(stateID: .hidSystemState) else {
+            return nil
+        }
+
+        guard
+            let keyDown = eventFactory.make(source: source, virtualKey: 0x09, keyDown: true),
+            let keyUp = eventFactory.make(source: source, virtualKey: 0x09, keyDown: false)
+        else {
+            return nil
+        }
+
+        keyDown.flags = .maskCommand
+        keyUp.flags = .maskCommand
+
+        return { [poster] in
+            poster.post(keyDown, tap: .cghidEventTap)
+            poster.post(keyUp, tap: .cghidEventTap)
+        }
+    }
+}
